#include<bits/stdc++.h>
using namespace std;
char ask(int al,int ar,int bl,int br)
{
    printf("1 %d ",ar-al+1);
    for(int i=al;i<=ar;i++)
    {
        printf("%d ",i);
    }
    printf("%d",br-bl+1);
    for(int i=bl;i<=br;i++)
    {
        printf(" %d",i);
    }
    printf("\n");
    fflush(stdout);
    char ch;
    cin>>ch;
    return ch;
}
void printans(int x,int y)
{
    printf("2 %d %d\n",x,y);
    exit(0);
}
vector<int> dfs(int l,int r,int cnt)
{
    if(l>r||cnt==0)
    {
        return vector<int>();
    }
    if(r-l+1==cnt)
    {
        vector<int> v;
        for(int i=l;i<=r;i++)
        {
            v.push_back(i);
        }
        return v;
    }
    if(l+1==r)
    {
        char now=ask(l,l,r,r);
        if(now=='<')
        {
            return vector<int>(1,l);
        }
        else
        {
            return vector<int>(1,r);
        }
        return vector<int>();
    }
    if(cnt==1)
    {
        int len=(r-l+1)/3;
        int mid1=l+len-1,mid2=l+len*2-1;
        char now=ask(l,mid1,mid1+1,mid2);
        if(now=='<')
        {
            return dfs(l,mid1,1);
        }
        else if(now=='>')
        {
            return dfs(mid1+1,mid2,1);
        }
        else
        {
            return dfs(mid2+1,r,1);
        }
        return vector<int>();
    }
    if((r-l+1)%2==0)
    {
        vector<int> v;
        int mid=(l+r)/2;
        char now=ask(l,mid,mid+1,r);
        if(now=='<')
        {
            return dfs(l,mid,2);
        }
        else if(now=='>')
        {
            return dfs(mid+1,r,2);
        }
        else
        {
            v=dfs(l,mid,1);
            vector<int> v1=dfs(mid+1,r,1);
            for(int i:v1)
            {
                v.push_back(i);
            }
            return v;
        }
        return vector<int>();
    }
    int mid=(l+(r-1))/2;
    char now=ask(l,mid,mid+1,r-1);
    if(now=='<')
    {
        if(ask(r,r,mid+1,mid+1)=='=')
        {
            return dfs(l,mid,2);
        }
        else
        {
            vector<int> v=dfs(l,mid,1);
            v.push_back(r);
            return v;
        }
        return vector<int>();
    }
    else if(now=='=')
    {
        vector<int> v;
        int x=dfs(l,mid,1)[0];
        v.push_back(x);
        int y=dfs(mid+1,r,1)[0];
        v.push_back(y);
        return v;
    }
    if(ask(r,r,mid,mid)=='=')
    {
        return dfs(mid+1,r-1,2);
    }
    else
    {
        vector<int> v=dfs(mid+1,r-1,1);
        v.push_back(r);
        return v;
    }
    return vector<int>();
}
int main()
{
    int n;
    scanf("%d",&n);
    vector<int> ans=dfs(1,n,2);
    printans(ans[0],ans[1]);
    return 0;
}
